content.problemStatement:
You are given an Array and you have to output all possible subsets of that array.

For Example:
Let the array Arr = [1, 2, 3], It's possible subsets include:


{}
{1}
{2}
{3}
{1, 2}
{2, 3}
{1, 3}
{1, 2, 3}
**Note** - Print the subsets in sorted order.


Input Format

The first line of input will contain a single integer NNN, denoting the number of integers in the array.
The second line contains NNN integers.


Output Format
Output All the possible subsets of the given array.

code.C:
#include <stdio.h>
#include <stdlib.h>

int cmp(const void *a, const void *b) { return (*(int*)a) - (*(int*)b); }

void dfs(int idx, int n, int *arr, int *temp, int sz) {
    if (idx == n) {
        if (sz == 0) return; // skip empty set
        for (int i = 0; i < sz; ++i) {
            if (i) printf(" ");
            printf("%d", temp[i]);
        }
        printf("\n");
        return;
    }
    // include arr[idx]
    temp[sz] = arr[idx];
    dfs(idx + 1, n, arr, temp, sz + 1);
    // exclude arr[idx]
    dfs(idx + 1, n, arr, temp, sz);
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *arr = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &arr[i]);
        qsort(arr, N, sizeof(int), cmp);
        int *temp = (int*)malloc(N * sizeof(int));
        dfs(0, N, arr, temp, 0);
        free(temp);
        free(arr);
    }
    return 0;
}

code.C++:
#include <bits/stdc++.h>
using namespace std;

void dfs(int idx, const vector<int>& a, vector<int>& cur) {
    if (idx == (int)a.size()) {
        if (cur.empty()) return; // skip empty set
        for (size_t i = 0; i < cur.size(); ++i) {
            if (i) cout << ' ';
            cout << cur[i];
        }
        cout << '\n';
        return;
    }
    // include a[idx]
    cur.push_back(a[idx]);
    dfs(idx + 1, a, cur);
    cur.pop_back();
    // exclude a[idx]
    dfs(idx + 1, a, cur);
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin >> T)) return 0;
    while (T--) {
        int N; cin >> N;
        vector<int> a(N);
        for (int &x : a) cin >> x;
        sort(a.begin(), a.end());
        vector<int> cur;
        dfs(0, a, cur);
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;

public class Main {
    static void dfs(int idx, int[] arr, List<Integer> cur, StringBuilder out) {
        if (idx == arr.length) {
            if (cur.isEmpty()) return; // skip empty set
            for (int i = 0; i < cur.size(); i++) {
                if (i > 0) out.append(' ');
                out.append(cur.get(i));
            }
            out.append('\n');
            return;
        }
        // include
        cur.add(arr[idx]);
        dfs(idx + 1, arr, cur, out);
        cur.remove(cur.size() - 1);
        // exclude
        dfs(idx + 1, arr, cur, out);
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder sb = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            int[] arr = new int[N];
            StringTokenizer st = new StringTokenizer(br.readLine());
            for (int i = 0; i < N; i++) arr[i] = Integer.parseInt(st.nextToken());
            Arrays.sort(arr);
            dfs(0, arr, new ArrayList<>(), sb);
        }
        System.out.print(sb.toString());
    }
}

