const fs = require('fs');
const data = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let pos = 0;
const T = Number(data[pos++]);
let output = [];
function dfs(idx, arr, cur) {
    if (idx === arr.length) {
        if (cur.length === 0) return; // skip empty set
        output.push(cur.join(' '));
        return;
    }
    cur.push(arr[idx]);
    dfs(idx + 1, arr, cur);
    cur.pop();
    dfs(idx + 1, arr, cur);
}
for (let t = 0; t < T; t++) {
    const N = Number(data[pos++]);
    let arr = [];
    for (let i = 0; i < N; i++) arr.push(Number(data[pos++]));
    arr.sort((a, b) => a - b);
    dfs(0, arr, []);
}
